Here are the public test cases for feature10_parameterized_and_prepared_queries:
{
  "description": "Execute a parameterized query and return field names, command tag, and row data.",
  "cases": [
    {
      "input": {
        "operation": "parameterized_query_results",
        "sql": "select $1::text as msg",
        "parameters": [
          "Hello, world"
        ]
      },
      "expected_output": "fields=msg\ncommand_tag=SELECT 1\nrow_count=1\nrow.0=Hello, world\n"
    }
  ]
}

