      "expected_output": "status=ok\nhost=123.123.123.123\nport=7777\ndatabase=foo\nuser=bar\npassword=baz\nconnect_timeout_seconds=10\ntls=disabled\nruntime_params={\"application_name\":\"pgxtest\"}\nvalidate_connect=false\nfallback_count=0\n"
    }
  ]
}

